This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define i1 @xor_logic_and_logic_or2_commuted(i1 %c, i1 %x, i1 %y) {
  %o = select i1 %y, i1 true, i1 %c
  %a = select i1 %c, i1 %x, i1 false
  %r = xor i1 %o, %a
  ret i1 %r
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define i1 @xor_logic_and_logic_or2_commuted(i1 %c, i1 %x, i1 %y) {
  %1 = xor i1 %x, true
  %r = select i1 %c, i1 %1, i1 %y
  ret i1 %r
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp:InstCombinerImpl::visitXor to implement the missed optimization:
```cpp
      match(Op1, m_OneUse(m_Or(m_Value(C), m_Value(D))))) {
    if (B == C || B == D)
      std::swap(A, B);
    if (A == C)
      std::swap(C, D);
    if (A == D) {
      Value *NotA = Builder.CreateNot(A);
      return BinaryOperator::CreateAnd(Builder.CreateXor(B, C), NotA);
    }
  }

  // (A & B) ^ (A | C) --> A ? ~B : C -- There are 4 commuted variants.
  if (I.getType()->isIntOrIntVectorTy(1) &&
      match(Op0, m_OneUse(m_LogicalAnd(m_Value(A), m_Value(B)))) &&
      match(Op1, m_OneUse(m_LogicalOr(m_Value(C), m_Value(D))))) {
    bool NeedFreeze = isa<SelectInst>(Op0) && isa<SelectInst>(Op1) && B == D;
    if (B == C || B == D)
      std::swap(A, B);
    if (A == C)
      std::swap(C, D);
    if (A == D) {
      if (NeedFreeze)
        A = Builder.CreateFreeze(A);
      Value *NotB = Builder.CreateNot(B);
      return SelectInst::Create(A, NotB, C);
    }
  }

```

